#include <stdio.h>
#include <math.h>

// Function to calculate average rotational latency in ms
double avgRotationalLatency(int rpm) {
    return (60.0 / (2.0 * rpm)) * 1000;  // Convert to milliseconds
}

// Function to calculate transfer time in ms
double transferTime(int fileSizeKB, double transferRateMBps) {
    return (fileSizeKB / transferRateMBps);  // Result in milliseconds
}

// Function to calculate total disk access time
double diskAccessTime(double seekTimeMs, int rpm, 
                      int fileSizeKB, double transferRateMBps,
                      double controllerOverheadMs) {
    double rotLatency = avgRotationalLatency(rpm);
    double transTime = transferTime(fileSizeKB, transferRateMBps);

    return seekTimeMs + rotLatency + transTime + controllerOverheadMs;
}

int main() {
    // Disk parameters
    double seekTime = 5.0;        // ms
    int rpm = 10000;              // rotations per minute
    int fileSizeKB = 10;          // file size in KB
    double transferRate = 50.0;  // MB/s
    double controllerOverhead = 1.0; // ms

    printf("=== Disk Access Time Calculator ===\n\n");

    double rotLatency = avgRotationalLatency(rpm);
    double transTime = transferTime(fileSizeKB, transferRate);
    double totalTime = diskAccessTime(seekTime, rpm, fileSizeKB, 
                                       transferRate, controllerOverhead);

    printf("Disk Parameters:\n");
    printf("  Seek Time: %.2f ms\n", seekTime);
    printf("  RPM: %d\n", rpm);
    printf("  Transfer Rate: %.2f MB/s\n", transferRate);
    printf("  File Size: %d KB\n", fileSizeKB);
    printf("  Controller Overhead: %.2f ms\n\n", controllerOverhead);

    printf("Time Components:\n");
    printf("  Seek Time: %.2f ms\n", seekTime);
    printf("  Rotational Latency (avg): %.2f ms\n", rotLatency);
    printf("  Transfer Time: %.2f ms\n", transTime);
    printf("  Controller Overhead: %.2f ms\n\n", controllerOverhead);

    printf("TOTAL DISK ACCESS TIME: %.2f ms\n", totalTime);

    return 0;
}
